<div class="py-6">
    <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 class="text-2xl font-semibold text-gray-900 dark:text-white mb-6">Vendor Profile</h1>

        <!-- Progress -->
        <div class="mb-6">
            <div class="flex justify-between items-center mb-2">
                <span class="text-sm font-medium text-gray-700 dark:text-gray-300">88% Complete</span>
                <span class="text-sm text-gray-500 dark:text-gray-400">Business Details • Location • Services • Social • FAQs • Images • Videos • Packages</span>
            </div>
            <div class="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2.5">
                <div class="bg-primary-600 h-2.5 rounded-full" style="width: 88%"></div>
            </div>
        </div>

        <!-- Form -->
        <div class="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-6">
            <h2 class="text-lg font-medium text-gray-900 dark:text-white mb-4">Business Details</h2>
            <div class="space-y-4">
                <div>
                    <label class="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Trading Name (Public Business Name) *</label>
                    <input type="text" value="Royal Wedding Planners" class="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white">
                </div>
                <div>
                    <label class="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Category</label>
                    <select class="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white">
                        <option>Venue</option>
                    </select>
                </div>
                <div>
                    <label class="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Business Type *</label>
                    <select class="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white">
                        <option>Sole Trader / Self-Employed</option>
                    </select>
                    <p class="text-xs text-gray-500 dark:text-gray-400 mt-1">Once saved here, the business type cannot be changed later.</p>
                </div>
                <div>
                    <label class="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Description *</label>
                    <textarea rows="3" class="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white">We provide premium wedding planning and decoration services. vxvcv</textarea>
                </div>
                <div>
                    <label class="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Features *</label>
                    <p class="text-xs text-gray-500 dark:text-gray-400 mb-2">Provide a detailed description of your business (minimum 20 characters)</p>
                    <div class="flex flex-wrap gap-2">
                        <span class="px-3 py-1 bg-gray-100 dark:bg-gray-700 rounded-full text-sm flex items-center">
                            Indoor Hall <button class="ml-2 text-gray-500 hover:text-gray-700">×</button>
                        </span>
                        <span class="px-3 py-1 bg-gray-100 dark:bg-gray-700 rounded-full text-sm flex items-center">
                            Outdoor Garden <button class="ml-2 text-gray-500 hover:text-gray-700">×</button>
                        </span>
                        <span class="px-3 py-1 bg-gray-100 dark:bg-gray-700 rounded-full text-sm flex items-center">
                            Catering <button class="ml-2 text-gray-500 hover:text-gray-700">×</button>
                        </span>
                        <span class="px-3 py-1 bg-gray-100 dark:bg-gray-700 rounded-full text-sm flex items-center">
                            Parking <button class="ml-2 text-gray-500 hover:text-gray-700">×</button>
                        </span>
                    </div>
                </div>
                <div>
                    <label class="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Licences & Insurance (Category-Based)</label>
                    <p class="text-xs text-gray-500 dark:text-gray-400 mb-2">Documents are REQUIRED for your category to go live. Please upload relevant compliance documentation.</p>
                    <div class="border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-lg p-6 text-center">
                        <x-heroicon-s-cloud-arrow-up class="mx-auto h-12 w-12 text-gray-400" />
                        <p class="mt-2 text-sm text-gray-600 dark:text-gray-400">Drag & drop your documents here or <span class="text-primary-600">browse files</span></p>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>